      for (int j = 1; j <= N; j++) {
        if (s.charAt(i - 1) == t.charAt(j - 1)) {
          d[i][j] = d[i - 1][j - 1] + 1;
        } else {
          d[i][j] = 0;
        }

        if (d[i][j] > max) {
          max = d[i][j];
        }
      }
    }

    return max;
  }

  
  public static int editDistance(String s, String t) {

    int n = s.length(); 
    int m = t.length(); 
    if (n == 0) {
      return m;
    }
    if (m == 0) {
      return n;
    }
    int[][] d = new int[n + 1][m + 1]; 

    for (int i = 0; i <= n; i++) {
      d[i][0] = i;
    }
    for (int j = 0; j <= m; j++) {
      d[0][j] = j;
    }

    for (int i = 1; i <= n; i++) {
      char s_i = s.charAt(i - 1); 

      for (int j = 1; j <= m; j++) {
        char t_j = t.charAt(j - 1); 

        int cost; 
        if (s_i == t_j) {
          cost = 0;
        } else {
          cost = 1;
        }

        d[i][j] = SloppyMath.min(d[i - 1][j] + 1, d[i][j - 1] + 1, d[i - 1][j - 1] + cost);
      }
    }


    return d[n][m];
  }


  
